// ===== STARFIELD =====
  const canvas = document.getElementById('stars-canvas');
  const ctx = canvas.getContext('2d');
  let stars = [];

  function resizeCanvas() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
  }

  function initStars() {
    stars = [];
    for (let i = 0; i < 180; i++) {
      stars.push({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        size: Math.random() * 2 + 0.5,
        speed: Math.random() * 0.3 + 0.05,
        brightness: Math.random(),
        twinkleSpeed: Math.random() * 0.02 + 0.005
      });
    }
  }

  function drawStars() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    const t = Date.now() * 0.001;
    stars.forEach(star => {
      const alpha = 0.4 + 0.6 * Math.abs(Math.sin(t * star.twinkleSpeed * 60 + star.brightness * 100));
      ctx.fillStyle = `rgba(255, 255, 255, ${alpha})`;
      ctx.fillRect(Math.floor(star.x), Math.floor(star.y), Math.ceil(star.size), Math.ceil(star.size));
      star.y += star.speed;
      if (star.y > canvas.height) { star.y = 0; star.x = Math.random() * canvas.width; }
    });
    requestAnimationFrame(drawStars);
  }

  resizeCanvas(); initStars(); drawStars();
  window.addEventListener('resize', () => { resizeCanvas(); initStars(); });

  // ===== SCROLL REVEAL =====
  const revealEls = document.querySelectorAll('.reveal');
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(el => {
      if (el.isIntersecting) {
        el.target.classList.add('visible');
        // Animate skill bars
        el.target.querySelectorAll('.skill-fill[data-width]').forEach(bar => {
          setTimeout(() => { bar.style.width = bar.dataset.width + '%'; }, 200);
        });
      }
    });
  }, { threshold: 0.15 });
  revealEls.forEach(el => observer.observe(el));

  // Also animate skills that are already in view on load
  document.querySelectorAll('.skill-fill[data-width]').forEach(bar => {
    const rect = bar.getBoundingClientRect();
    if (rect.top < window.innerHeight) {
      setTimeout(() => { bar.style.width = bar.dataset.width + '%'; }, 600);
    }
  });

  // ===== SMOOTH SCROLL =====
  document.querySelectorAll('a[href^="#"]').forEach(a => {
    a.addEventListener('click', e => {
      e.preventDefault();
      const target = document.querySelector(a.getAttribute('href'));
      if (target) target.scrollIntoView({ behavior: 'smooth' });
      // Cerrar menú mobile si está abierto
      document.getElementById('mobile-menu').classList.remove('open');
      document.getElementById('hamburger').classList.remove('open');
    });
  });

  // ===== HAMBURGER MENU =====
  const hamburger  = document.getElementById('hamburger');
  const mobileMenu = document.getElementById('mobile-menu');
  if (hamburger && mobileMenu) {
    hamburger.addEventListener('click', () => {
      hamburger.classList.toggle('open');
      mobileMenu.classList.toggle('open');
    });
    // Cerrar al tocar fuera
    document.addEventListener('click', (e) => {
      if (!hamburger.contains(e.target) && !mobileMenu.contains(e.target)) {
        hamburger.classList.remove('open');
        mobileMenu.classList.remove('open');
      }
    });
  }

  // ===== PIXEL CLICK EFFECT =====
  document.addEventListener('click', (e) => {
    const sparkle = document.createElement('div');
    sparkle.style.cssText = `
      position: fixed; left: ${e.clientX - 8}px; top: ${e.clientY - 8}px;
      width: 16px; height: 16px; pointer-events: none; z-index: 9999;
      font-family: monospace; font-size: 16px; color: #FFD700;
      animation: sparkle-anim 0.6s ease forwards;
    `;
    sparkle.textContent = '✦';
    document.body.appendChild(sparkle);
    setTimeout(() => sparkle.remove(), 600);
  });

  const style = document.createElement('style');
  style.textContent = `
    @keyframes sparkle-anim {
      0% { opacity: 1; transform: scale(0.5) translateY(0); }
      100% { opacity: 0; transform: scale(1.5) translateY(-20px); }
    }
  `;
  document.head.appendChild(style);

/* ============================================================ */

(function() {
  const canvas   = document.getElementById('three-canvas');
  const hero     = document.getElementById('hero');
  const lblBikes = document.getElementById('label-bikes');
  const lblFerrari = document.getElementById('label-ferrari');

  // ── Renderer ──────────────────────────────────────────────
  const renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: true });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.outputEncoding = THREE.sRGBEncoding;
  renderer.shadowMap.enabled = false;

  // ── Scene & Camera ────────────────────────────────────────
  const scene  = new THREE.Scene();
  const camera = new THREE.PerspectiveCamera(55, 1, 0.1, 100);
  camera.position.set(0, 0, 7);

  // ── Lights ────────────────────────────────────────────────
  const ambient = new THREE.AmbientLight(0xffffff, 0.7);
  scene.add(ambient);

  const dirLight = new THREE.DirectionalLight(0x00e5ff, 1.2);
  dirLight.position.set(5, 8, 5);
  scene.add(dirLight);

  const rimLight = new THREE.DirectionalLight(0xFFD700, 0.6);
  rimLight.position.set(-5, -2, -3);
  scene.add(rimLight);

  // ── Pixel-art point lights (parpadeo) ─────────────────────
  const glowL = new THREE.PointLight(0x39FF14, 1.5, 5);
  glowL.position.set(-2.5, 0.5, 1);
  scene.add(glowL);

  const glowR = new THREE.PointLight(0xff3c3c, 1.5, 5);
  glowR.position.set(2.5, 0.5, 1);
  scene.add(glowR);

  // ── Helpers de animación ──────────────────────────────────
  let bikesModel   = null;
  let ferrariModel = null;
  let clock = new THREE.Clock();

  // ── GLB embebidos como base64 (funciona con file://) ───────
  const loader = new THREE.GLTFLoader();

  function b64ToArrayBuffer(b64) {
    const bin = atob(b64);
    const buf = new ArrayBuffer(bin.length);
    const view = new Uint8Array(buf);
    for (let i = 0; i < bin.length; i++) view[i] = bin.charCodeAt(i);
    return buf;
  }

  function setupModel(gltf, posX, rotY, emissiveColor) {
    const model = gltf.scene;
    const box   = new THREE.Box3().setFromObject(model);
    const size  = new THREE.Vector3();
    box.getSize(size);
    const maxDim = Math.max(size.x, size.y, size.z);
    const targetSize = getModelScale(1.4);
    const scale = targetSize / maxDim;
    model.scale.setScalar(scale);
    const center = new THREE.Vector3();
    new THREE.Box3().setFromObject(model).getCenter(center);
    model.position.sub(center);
    model.position.x = posX;
    model.position.y = getModelY();
    model.rotation.y = rotY;
    model.userData.baseX = posX;
    model.userData.baseY = getModelY();
    model.userData.baseRotY = rotY;
    model.traverse(child => {
      if (child.isMesh && child.material) {
        child.material.emissive = new THREE.Color(emissiveColor);
        child.material.emissiveIntensity = 0.3;
      }
    });
    scene.add(model);
    return model;
  }

  const BIKES_B64   = "";
  const FERRARI_B64 = "";

  loader.parse(b64ToArrayBuffer(BIKES_B64), '', (gltf) => {
    bikesModel = setupModel(gltf, getModelX(-1), 0.5, 0x001a33);
    adaptModels();
  }, (err) => console.warn('bikes error:', err));

  loader.parse(b64ToArrayBuffer(FERRARI_B64), '', (gltf) => {
    ferrariModel = setupModel(gltf, getModelX(1), -0.5, 0x1a0000);
    adaptModels();
  }, (err) => console.warn('ferrari error:', err));

  // ── Resize ────────────────────────────────────────────────
  // Devuelve ±X según ancho de pantalla
  function getModelX(sign) {
    const w = hero.clientWidth;
    if (w < 400)  return sign * 1.1;
    if (w < 600)  return sign * 1.4;
    if (w < 900)  return sign * 1.85;
    return sign * 2.8;
  }

  // Y elevada en mobile para quedar al nivel del personaje
  function getModelY() {
    const w = hero.clientWidth;
    const h = hero.clientHeight;
    const aspect = w / h;
    // En portrait (aspect < 1) el personaje está en la mitad superior
    // subimos el modelo para que quede junto a él
    if (aspect < 0.65)  return 1.8;   // móvil portrait estrecho
    if (aspect < 0.85)  return 1.2;   // móvil portrait ancho
    if (aspect < 1.1)   return 0.6;   // casi cuadrado (tablet portrait)
    return 0.0;                        // landscape / desktop
  }

  // Escala del modelo según ancho
  function getModelScale(baseScale) {
    const w = hero.clientWidth;
    if (w < 400)  return baseScale * 0.55;
    if (w < 600)  return baseScale * 0.68;
    if (w < 900)  return baseScale * 0.85;
    return baseScale;
  }

  // Reposicionar modelos al cambiar viewport
  function adaptModels() {
    [{ m: bikesModel, sign: -1 }, { m: ferrariModel, sign: 1 }].forEach(({ m, sign }) => {
      if (!m) return;
      m.userData.baseX = getModelX(sign);
      m.userData.baseY = getModelY();
    });
  }

  function onResize() {
    const w = hero.clientWidth || window.innerWidth;
    const h = hero.clientHeight || window.innerHeight * 0.9;
    renderer.setSize(w, h, false);
    camera.aspect = w / h;
    // En portrait mobile abrir más el FOV horizontal
    camera.fov = w < 600 ? 70 : 55;
    camera.updateProjectionMatrix();
    adaptModels();
  }
  onResize();
  window.addEventListener('resize', onResize);

  // ── Proyectar posición 3D a CSS 2D para los labels ────────
  function projectToScreen(obj, label) {
    if (!obj) return;
    const vec = new THREE.Vector3();
    obj.getWorldPosition(vec);
    vec.project(camera);

    const rect = hero.getBoundingClientRect();
    const x = (vec.x *  0.5 + 0.5) * rect.width;
    const y = (vec.y * -0.5 + 0.5) * rect.height;

    label.style.left = x + 'px';
    label.style.top  = (y + 80) + 'px';
    label.style.transform = 'translateX(-50%)';
  }

  // ── Loop ──────────────────────────────────────────────────
  function animate() {
    requestAnimationFrame(animate);
    const t = clock.getElapsedTime();

    // Flotación suave + giro 360° lento continuo
    if (bikesModel) {
      bikesModel.position.x  = (bikesModel.userData.baseX  !== undefined ? bikesModel.userData.baseX  : getModelX(-1));
      bikesModel.position.y  = (bikesModel.userData.baseY  !== undefined ? bikesModel.userData.baseY  : getModelY()) + Math.sin(t * 0.8) * 0.15;
      bikesModel.rotation.y  =  t * 0.45;
      bikesModel.rotation.x  =  Math.sin(t * 0.3) * 0.08;
      projectToScreen(bikesModel, lblBikes);
    }
    if (ferrariModel) {
      ferrariModel.position.x  = (ferrariModel.userData.baseX !== undefined ? ferrariModel.userData.baseX : getModelX(1));
      ferrariModel.position.y  = (ferrariModel.userData.baseY  !== undefined ? ferrariModel.userData.baseY  : getModelY()) + Math.sin(t * 0.8 + Math.PI) * 0.15;
      ferrariModel.rotation.y  =  t * 0.45 + Math.PI;
      ferrariModel.rotation.x  =  Math.sin(t * 0.3 + 1.0) * 0.08;
      projectToScreen(ferrariModel, lblFerrari);
    }

    // Parpadeo de las luces neón
    glowL.intensity = 1.0 + 0.5 * Math.sin(t * 3.0);
    glowR.intensity = 1.0 + 0.5 * Math.sin(t * 2.7 + 1.0);

    renderer.render(scene, camera);
  }
  animate();
})();